import React, { useEffect, useState } from 'react'
import { useNavigate } from 'react-router-dom';
import { CCol, CForm, CButton, CFormLabel} from "@coreui/react";
import FormInput from 'src/utils/FormInput';
import authService from 'src/auth/auth.service';
import GoBackComponent from 'src/utils/GoBackComponent';
import { paymentTypeOptions, validateEmail } from 'src/utils/Common';
import { createPaymentLink } from 'src/components/services/SubscriptionApi';
import Select from 'react-select';
import { getProductList, getSignupUserListData } from 'src/components/services/ProductApi';
import { getEnablePlanList } from 'src/components/services/SubscriptionPlanApi';
import TextArea from 'src/utils/TextArea';


const PaymentLinkForm = (props) => {
    const { type } = props;
    const [userData] = useState(authService.getUserDetailsFromLocalStorage())
    const [formData, setFormData] = useState({ email: "", amount: "", discount: "", netAmount: '', description: ''});
    const [selectCategory, setSelectCategory] = useState({ productCategory: {}, paymentType: {}, subscriptionPlanType: {}, signupUser: {} })
    const [selectOptions, setSelectOptions] = useState({productListOption: [], enableSubscriptionDetails: [], signupUserOptions: []});
    const [errors, setErrors] = useState({});
    const [errorMessage, setErrorMessage] = useState("");
    const navigate = useNavigate();
    const { productCategory, paymentType, subscriptionPlanType, signupUser } = selectCategory;
    const { productListOption, enableSubscriptionDetails, signupUserOptions } = selectOptions;

    useEffect(() => {
        getSignupUserList();
        getProductsList();
        getEnableSubscriptionPlan();
    }, [])


    const getSignupUserList = async() => {
        let data = {
            page: 0,
            size: 100,
        }
        const response = await getSignupUserListData(data);
        if (response?.status === "200 OK") {
            setSelectOptions(prevState => ({ ...prevState, signupUserOptions: response?.body && response?.body?.content && response?.body.content.map(item => ({value: item?.userId, label: item?.email})) }));
        }
    }

    const getProductsList = async() => {
        const response = await getProductList();
        if (response?.status === "200 OK") {
            setSelectOptions(prevState => ({ ...prevState, productListOption: response?.body && response?.body.map(item => ({value: item?.id, label: item?.name})) }));
        }
    }

    const getEnableSubscriptionPlan = async() => {
        const response = await getEnablePlanList();
        if (response?.status === "200 OK") {
            setSelectOptions(prevState => ({ ...prevState, enableSubscriptionDetails: response?.body}));
        }
    }

    const handleChange = (event) => {
        setFormData({ ...formData, [event.target.name]: event.target.name === "email" ? event.target.value.trimStart().replace(/  +/g, ' ') : event.target.name === "description" ? event.target.value : event.target.value.replace(/[^0-9]/g, "") });
    };

    const handleSelectCategory = (selectOption, type) => {
        setSelectCategory((prevData) => ({ ...prevData, [type]: selectOption }));
        if(type === "subscriptionPlanType"){
            let findSubscriptipnDetailsById = enableSubscriptionDetails && enableSubscriptionDetails.find(item => item?.id === selectOption?.value);
            setFormData({ ...formData, amount: findSubscriptipnDetailsById?.amount, discount: '', netAmount: ''});
        }
    };

    const handleChangeDiscount = (event) => {
        const discountPercentage = event.target.value.replace(/[^0-9]/g, ""); 
        /* Calculate discount and net amount */
        const discountAmount = parseInt((formData?.amount * discountPercentage) / 100);
        const netAmountValue = formData?.amount - discountAmount;      
        setFormData({...formData, [event.target.name]: discountPercentage, netAmount: discountPercentage ? netAmountValue : ''})
    };

    const validateForm = () => {
        let errors = {};
        let formIsValid = true;

        if (!signupUser?.value) {
            errors['email'] = "Please select an email";
            formIsValid = false;
        }
        if(formData.email && !validateEmail(formData.email)) {
            errors['email'] = "Please enter a valid email address";
            formIsValid = false;
        }
        // if (!formData.amount) {
        //     errors['amount'] = "Please enter amount";
        //     formIsValid = false;
        // }
        if (!productCategory?.value) {
            errors['productCategory'] = "Please select product type";
            formIsValid = false;
        }
        if (!paymentType?.value) {
            errors['paymentType'] = "Please select payment type";
            formIsValid = false;
        }
        if (!subscriptionPlanType?.value) {
            errors['subscriptionPlanType'] = "Please select plan type";
            formIsValid = false;
        }
        // if (!formData.discount) {
        //     errors['discount'] = "Please enter discount";
        //     formIsValid = false;
        // }
        if (!formData.description) {
            errors['description'] = "Please enter description";
            formIsValid = false;
        }
        setErrors(errors);
        setTimeout(() => {
            setErrors({});
        }, 2000);
        return formIsValid;
    }

    const handleSubmit = async (event) => {
        event.preventDefault();
        if (validateForm()) {
            let postData = {
                email: signupUser?.label,
                description: formData?.description,
                baseAmount: formData?.amount,
                paymentReceiveType:paymentType?.value,
                discount: formData?.discount ? formData?.discount : "0",
                subscriptionId: subscriptionPlanType?.value,
                productId:  productCategory?.value
            }
            let response = {};
            if (type === "CREATE") {
                response = await createPaymentLink(postData);
            }
            if (response?.status === "201 CREATED" || response?.code === 202) {
                navigate(`/member-details/${signupUser?.value}`,{ state: { activeTab: "SUBSCRIPTION_HISTORY" } });
            }
            if (response?.code === 409) {
                setErrorMessage(response?.message);
            }
            setTimeout(() => {
                setErrorMessage("");
            }, 2000);
        }
    };


    return (
        <>
            <GoBackComponent goBackData={"members-summary"} />
            <div className='customContainer'>
                <CForm className="row g-3">
                    <CCol md={10}>
                        <CFormLabel >User Email <span className="text-danger">*</span></CFormLabel>
                        <Select
                            options={signupUserOptions}
                            placeholder={"Select user email"}
                            onChange={(selectedOption) => handleSelectCategory(selectedOption, 'signupUser')}
                            classNamePrefix="select"
                            styles={{
                                option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                    const color = '#03a68059';
                                    return {
                                        ...styles,
                                        backgroundColor: isDisabled ? null : isSelected ? '#03a68059' : isFocused ? '#03a68059': null,
                                        color: isDisabled? '#ccc' : isSelected ? color > 2 ? '#00374d' : '#00374d' : data.color, cursor: isDisabled ? 'not-allowed' : 'default',
                                        ':active': { ...styles[':active'], backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059')},
                                    }
                                },
                                control: (provided, state) => ({...provided, minHeight: '50px', width: "100% ", borderRadius:'8px' , borderColor: state.isFocused ? '#03a680' : '#ced4da',}),
                            }}
                        />
                         {errors["email"] && <span style={{color: 'red'}}>{errors["email"]}</span>}
                        {errorMessage && <span style={{ color: "red" }}>{errorMessage}</span>}
                    </CCol>
                    <CCol md={10}>
                        <CFormLabel >Products <span className="text-danger">*</span></CFormLabel>
                        <Select
                            options={productListOption}
                            placeholder={"Select product type"}
                            //value={productCategory}
                            onChange={(selectedOption) => handleSelectCategory(selectedOption, 'productCategory')}
                            classNamePrefix="select"
                            styles={{
                                option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                    const color = '#03a68059';
                                    return {
                                        ...styles,
                                        backgroundColor: isDisabled ? null : isSelected ? '#03a68059' : isFocused ? '#03a68059': null,
                                        color: isDisabled? '#ccc' : isSelected ? color > 2 ? '#00374d' : '#00374d' : data.color, cursor: isDisabled ? 'not-allowed' : 'default',
                                        ':active': { ...styles[':active'], backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059')},
                                    }
                                },
                                control: (provided, state) => ({...provided, minHeight: '50px', width: "100% ", borderRadius:'8px' , borderColor: state.isFocused ? '#03a680' : '#ced4da',}),
                            }}
                        />
                        {errors["productCategory"] && <span style={{color: 'red'}}>{errors["productCategory"]}</span>}
                    </CCol>

                    <CCol md={10}>
                        <CFormLabel >Plan <span className="text-danger">*</span></CFormLabel>
                        <Select
                            options={enableSubscriptionDetails && enableSubscriptionDetails.map(item => ({value: item?.id, label: item?.subscriptionPlanType}))}
                            placeholder={"Select plan"}
                            //value={productCategory}
                            onChange={(selectedOption) => handleSelectCategory(selectedOption, 'subscriptionPlanType')}
                            classNamePrefix="select"
                            styles={{
                                option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                    const color = '#03a68059';
                                    return {
                                        ...styles,
                                        backgroundColor: isDisabled ? null : isSelected ? '#03a68059' : isFocused ? '#03a68059': null,
                                        color: isDisabled? '#ccc' : isSelected ? color > 2 ? '#00374d' : '#00374d' : data.color, cursor: isDisabled ? 'not-allowed' : 'default',
                                        ':active': { ...styles[':active'], backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059')},
                                    }
                                },
                                control: (provided, state) => ({...provided, minHeight: '50px', width: "100% ", borderRadius:'8px' , borderColor: state.isFocused ? '#03a680' : '#ced4da',}),
                            }}
                        />
                        {errors["subscriptionPlanType"] && <span style={{color: 'red'}}>{errors["subscriptionPlanType"]}</span>}
                    </CCol>

                    <CCol md={10}>
                        <CFormLabel >Payment Type <span className="text-danger">*</span></CFormLabel>
                        <Select
                            options={paymentTypeOptions && paymentTypeOptions.map(item => ({value: item, label: item.replace(/_/g, ' ')}))}
                            placeholder={"Select payment type"}
                            onChange={(selectedOption) => handleSelectCategory(selectedOption, 'paymentType')}
                            classNamePrefix="select"
                            styles={{
                                option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                    const color = '#03a68059';
                                    return {
                                        ...styles,
                                        backgroundColor: isDisabled ? null : isSelected ? '#03a68059' : isFocused ? '#03a68059': null,
                                        color: isDisabled? '#ccc' : isSelected ? color > 2 ? '#00374d' : '#00374d' : data.color, cursor: isDisabled ? 'not-allowed' : 'default',
                                        ':active': { ...styles[':active'], backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059')},
                                    }
                                },
                                control: (provided, state) => ({...provided, minHeight: '50px', width: "100% ", borderRadius:'8px' , borderColor: state.isFocused ? '#03a680' : '#ced4da',}),
                            }}
                        />
                        {errors["paymentType"] && <span style={{color: 'red'}}>{errors["paymentType"]}</span>}
                    </CCol>


                    <CCol md={5}>
                        <FormInput
                            disabled
                            value={formData.amount}
                            label={"Amount"}
                            required
                            name={"amount"}
                            onChange={handleChange}
                            error={errors['amount']}
                        />
                    </CCol>
                    <CCol md={5}>
                        <FormInput
                            value={formData?.discount}
                            label={"Discount"}
                            name={"discount"}
                            onChange={handleChangeDiscount}
                            // error={errors['discount']}
                        />
                    </CCol>
                    <CCol md={5}>
                        <FormInput
                            disabled
                            value={formData?.discount ? formData.netAmount : formData.amount}
                            label={"Net Amount"}
                            required
                            name={"netAmount"}
                            onChange={handleChange}
                            error={errors['netAmount']}
                        />
                    </CCol>
                    <CCol md={12}>
                        <TextArea
                          value={formData.description}
                          label={"Description"}
                          required
                          name={"description"}
                          onChange={handleChange}
                          error={errors['description']}
                        />
                    </CCol>


                   {authService.getPermission("PAYMENT_LINK_CREATE") && 
                    <CCol md={12}>
                        <CButton color="primary" onClick={handleSubmit} className="d-block">
                            {"Create"}
                        </CButton>
                    </CCol>}
                </CForm>
            </div>
        </>
    )
}

export default PaymentLinkForm;
